import { HTMLAttributes, ReactNode } from "react";

import { Card, CardContent } from "@/components/ui/card";

export type ShadcnDayProps = Omit<HTMLAttributes<HTMLDivElement>, "title"> & {
    logo?: ReactNode;
    logoText?: string;
    title?: ReactNode;
    date?: string;
};

const shadcnLogo = (
    <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 256 256"
        className="size-8 transition-transform duration-500 group-hover:rotate-12">
        <rect width="256" height="256" fill="none"></rect>
        <line
            x1="208"
            y1="128"
            x2="128"
            y2="208"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth="24"></line>
        <line
            x1="192"
            y1="40"
            x2="40"
            y2="192"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth="24"></line>
    </svg>
);

export function ShadcnDay({
    logo = shadcnLogo,
    logoText = "shadcn",
    title,
    date = "19 May",
    ...props
}: ShadcnDayProps) {
    return (
        <Card
            {...props}
            className={`group relative overflow-hidden transition-all duration-300 hover:-translate-y-1 ${props.className || ""}`}>
            <CardContent className="relative flex w-full flex-col items-center justify-center md:p-8">
                <div className="flex items-center gap-3">
                    <div className="rounded-lg border p-1.5 shadow-xs">{logo}</div>
                    {logoText && <span className="text-3xl font-medium">{logoText}</span>}
                </div>

                {title && (
                    <h1 className="from-foreground to-foreground/70 mt-8 bg-linear-to-br bg-clip-text text-center text-5xl font-extrabold tracking-tight text-transparent md:mt-10 md:text-6xl xl:mt-12">
                        {title}
                    </h1>
                )}

                <div className="mt-8 flex w-full max-w-xs items-center md:mt-10 xl:mt-12">
                    <div className="h-0.5 w-full bg-linear-to-r from-transparent to-red-500"></div>
                    <div className="relative mx-6 shrink-0">
                        <svg
                            xmlns="http://www.w3.org/2000/svg"
                            viewBox="0 0 24 24"
                            className="relative size-7 animate-pulse fill-red-500 transition-transform duration-300 group-hover:scale-110">
                            <path d="M11.645 20.91l-.007-.003-.022-.012a15.247 15.247 0 01-.383-.218 25.18 25.18 0 01-4.244-3.17C4.688 15.36 2.25 12.174 2.25 8.25 2.25 5.322 4.714 3 7.688 3A5.5 5.5 0 0112 5.052 5.5 5.5 0 0116.313 3c2.973 0 5.437 2.322 5.437 5.25 0 3.925-2.438 7.111-4.739 9.256a25.175 25.175 0 01-4.244 3.17 15.247 15.247 0 01-.383.219l-.022.012-.007.004-.003.001a.752.752 0 01-.704 0l-.003-.001z" />
                        </svg>
                    </div>
                    <div className="h-0.5 w-full bg-linear-to-l from-transparent to-red-500"></div>
                </div>

                {date && (
                    <div className="group-hover:text-foreground mt-8 rounded-full border px-6 py-2 text-2xl font-semibold shadow-xs md:mt-10 md:text-3xl xl:mt-12">
                        {date}
                    </div>
                )}
            </CardContent>
        </Card>
    );
}
